// Validate incoming payload
const body = $input.first().json.body || $input.first().json;

if (!body.issueKey)   throw new Error('issueKey is required');
if (!body.jiraUrl)    throw new Error('jiraUrl is required');
if (!body.jiraEmail)  throw new Error('jiraEmail is required');
if (!body.jiraToken)  throw new Error('jiraToken is required');

const provider = body.provider || 'openai';
const hasKey = body.openaiKey || body.claudeKey || body.geminiKey;
if (!hasKey) throw new Error('At least one AI provider API key is required');

// Build basic auth header for Jira
const basicAuth = 'Basic ' + Buffer.from(body.jiraEmail + ':' + body.jiraToken).toString('base64');

return [{
  json: {
    issueKey:  body.issueKey,
    jiraUrl:   body.jiraUrl.replace(/\/$/, ''),
    jiraEmail: body.jiraEmail,
    jiraToken: body.jiraToken,
    provider,
    model:     body.model || null,
    openaiKey: body.openaiKey || '',
    claudeKey: body.claudeKey || '',
    geminiKey: body.geminiKey || '',
    language:   body.language  || 'javascript',
    taskType:   body.taskType  || 'code',
    repoContext: (body.repoContext && typeof body.repoContext === 'object') ? body.repoContext : {},
    basicAuth,
  },
}];

// Extract plain text from Atlassian Document Format (ADF) or plain string
function extractText(node) {
  if (!node) return '';
  if (typeof node === 'string') return node;
  if (node.type === 'text') return node.text || '';
  if (Array.isArray(node.content)) return node.content.map(extractText).join('\n');
  return '';
}

const issue    = $input.first().json;
const prev     = $('Validate & Prepare').first().json;
const summary  = issue.fields.summary || '';
const descText = extractText(issue.fields.description).trim() || 'No description provided.';
const language = prev.language || 'javascript';

const LANG_HINTS = {
  javascript: 'Use Node.js with modern ES2022+ syntax. Structure as modules with clear separation of concerns. Add JSDoc comments.',
  typescript: 'Use TypeScript with strict mode. Define interfaces/types for all data structures. Add TSDoc comments.',
  python:     'Use Python 3.11+. Follow PEP 8. Use type hints. Include docstrings. Write pytest unit tests.',
  java:       'Use Java 17+ with Spring Boot 3.x (Controller → Service → Repository). Apply Jakarta Validation. Include Javadoc. Write JUnit 5 + Mockito tests.',
  csharp:     'Use C# 12 / .NET 8. Follow clean architecture with dependency injection. Add XML doc comments. Write xUnit tests.',
  go:         'Use Go 1.22+. Follow standard Go project layout. Use interfaces for testability. Add godoc comments. Write table-driven tests.',
  rust:       'Use Rust (latest stable). Use idiomatic error handling with Result/Option. Add rustdoc comments.',
  php:        'Use PHP 8.3 with strict types. Follow PSR-12 standards. Use modern OOP patterns. Add PHPDoc comments.',
  ruby:       'Use Ruby 3.3+. Follow Ruby style guide. Use idiomatic Ruby patterns. Write RSpec tests.',
  kotlin:     'Use Kotlin with Spring Boot 3.x or Ktor. Use coroutines for async. Add KDoc comments. Write JUnit 5 tests.',
  swift:      'Use Swift 5.9+. Follow Swift API design guidelines. Use async/await for concurrency. Add documentation comments.',
  cpp:        'Use C++17/20. Follow modern C++ best practices. Use smart pointers. Add Doxygen comments.',
};

const hint = LANG_HINTS[language] || `Write clean, well-structured ${language} code following best practices for the language.`;

const prompt = [
  `You are a senior ${language} developer.`,
  '',
  `Task: ${summary}`,
  '',
  `Description:\n${descText}`,
  '',
  'Requirements:',
  `- ${hint}`,
  '- Write production-ready, clean code with proper error handling.',
  '- Include meaningful comments where the logic is not self-evident.',
  '- Structure files logically (separate concerns into multiple files if appropriate).',
  '',
  'Return ONLY a valid JSON object — no markdown, no code fences — with this exact shape:',
  '{',
  '  "summary": "<one-sentence description of what was implemented>",',
  '  "files": [',
  '    { "name": "<relative/path/filename.ext>", "content": "<full file content>" }',
  '  ],',
  '  "patch": "<unified diff of all generated files (git diff format), or empty string>"',
  '}',
].join('\n');

const taskType = prev.taskType || 'code';
const repoCtx  = prev.repoContext || {};
const repoSection = Object.keys(repoCtx).length > 0
  ? ' | Repository Structures: ' + Object.entries(repoCtx).map(function(kv){return '[' + kv[0] + ']: ' + kv[1];}).join(' | ')
  : '';

let finalPrompt = prompt;
if (taskType !== 'code') {
  const TASK_NOTES = {
    explain: 'Business analysis: identify business rules, data flow, affected components (use repo structure if available), edge cases, acceptance criteria, recommended implementation approach.',
    bug:     'Debug: trace root cause step by step using repo structure, identify affected files, provide minimal targeted fix + regression test.',
    review:  'Code review: check for bugs, OWASP Top 10 security issues, performance, code quality, missing error handling. Reference specific files.',
    test:    'Tests: comprehensive unit + integration tests, edge cases, error scenarios, mocks/stubs. Stack: ' + hint + '.',
    docs:    'Documentation: overview, API reference, configuration, code examples, architecture notes.',
    refactor:'Refactor: apply SOLID principles, reduce complexity and duplication, improve readability. Stack: ' + hint + '.',
  };
  finalPrompt = 'TASK TYPE: ' + taskType + ' | INSTRUCTION: ' + (TASK_NOTES[taskType] || 'Implement as described.') + ' | Issue: ' + summary + ' | Description: ' + descText + repoSection + ' | Return ONLY valid JSON with keys: summary (string), files (array of {name, content}), patch (string).';
}

return [{
  json: {
    ...prev,
    issueKey: issue.key,
    summary,
    descText,
    language,
    taskType,
    prompt: finalPrompt,
  },
}];

// Route to the correct AI provider using the global fetch() available in n8n v1+
const { provider, model, openaiKey, claudeKey, geminiKey, prompt, language, taskType } = $json;
const TASK_ROLES = { explain: 'business analyst', bug: 'debugging expert', review: 'code reviewer', test: 'test engineer', docs: 'technical writer', refactor: 'refactoring specialist' };
const role = (taskType && TASK_ROLES[taskType]) ? TASK_ROLES[taskType] : 'software developer';
const SYSTEM = `You are a senior ${language || 'software'} ${role}. Return only valid JSON — no markdown, no explanation.`;

let content;

if (provider === 'claude') {
  const res = await fetch('https://api.anthropic.com/v1/messages', {
    method: 'POST',
    headers: { 'x-api-key': claudeKey, 'anthropic-version': '2023-06-01', 'Content-Type': 'application/json' },
    body: JSON.stringify({ model: model || 'claude-3-5-sonnet-20241022', max_tokens: 8192, system: SYSTEM, messages: [{ role: 'user', content: prompt }] }),
  });
  if (!res.ok) throw new Error(`Claude API error ${res.status}: ${await res.text()}`);
  const data = await res.json();
  content = data.content[0].text;

} else if (provider === 'gemini') {
  const mdl = model || 'gemini-1.5-pro';
  const res = await fetch(
    `https://generativelanguage.googleapis.com/v1beta/models/${mdl}:generateContent?key=${geminiKey}`,
    {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ contents: [{ parts: [{ text: `${SYSTEM}\n\n${prompt}` }] }], generationConfig: { temperature: 0.2, maxOutputTokens: 8192 } }),
    }
  );
  if (!res.ok) throw new Error(`Gemini API error ${res.status}: ${await res.text()}`);
  const data = await res.json();
  content = data.candidates[0].content.parts[0].text;

} else {
  // Default: OpenAI
  const res = await fetch('https://api.openai.com/v1/chat/completions', {
    method: 'POST',
    headers: { 'Authorization': `Bearer ${openaiKey}`, 'Content-Type': 'application/json' },
    body: JSON.stringify({ model: model || 'gpt-4o', temperature: 0.2, max_tokens: 8192, messages: [{ role: 'system', content: SYSTEM }, { role: 'user', content: prompt }] }),
  });
  if (!res.ok) throw new Error(`OpenAI API error ${res.status}: ${await res.text()}`);
  const data = await res.json();
  content = data.choices[0].message.content;
}

return [{ json: { ...$json, aiContent: content } }];

const { aiContent } = $input.first().json;
const rawContent = aiContent ?? '';

// Strip accidental markdown code fences
const cleaned = rawContent
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/\s*```$/, '')
  .trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch {
  throw new Error('AI did not return valid JSON. Raw: ' + cleaned.slice(0, 300));
}

if (!parsed.summary) parsed.summary = 'Code generated successfully.';
if (!Array.isArray(parsed.files)) parsed.files = [];
if (typeof parsed.patch !== 'string') parsed.patch = '';

return [{ json: parsed }];

// Error handler — return a structured error response instead of crashing
const err = $input.first().json;
return [{
  json: {
    error: true,
    message: err.message || 'Unknown error',
  },
}];
